static void updateCallGraphAfterCoroutineSplit(
    LazyCallGraph::Node &N, const coro::Shape &Shape,
    const SmallVectorImpl<Function *> &Clones, LazyCallGraph::SCC &C,
    LazyCallGraph &CG, CGSCCAnalysisManager &AM, CGSCCUpdateResult &UR,
    FunctionAnalysisManager &FAM) {
  // Add the new functions to the call graph.
  addSplitFunctionsToGraph(N, Clones, C, CG, AM, UR, FAM);

  // Do some cleanup and let the CGSCC infra see if we've cleaned up any edges
  // to the split functions.
  postSplitCleanup(N.getFunction());

  // The body of the original function has changed, and with it its calls.
  // We need to tell the LazyCallGraph to re-scan it. The most robust way
  // to do this when the API is unknown is to clear the whole graph.
  CG.clear();

